import{_ as l,C as o,o as n,c as s,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Italy Healthcare & HRT","description":"Transgender healthcare access in Italy","frontmatter":{"layout":"doc","title":"Italy Healthcare & HRT","description":"Transgender healthcare access in Italy"},"headers":[],"relativePath":"europe/italy/healthcare.md","filePath":"europe/italy/healthcare.md","lastUpdated":null}'),c={name:"europe/italy/healthcare.md"};function h(g,e,p,u,m,b){const t=o("Badge");return n(),s("div",null,[a(t,{variant:"yellow"},{default:i(()=>[...e[0]||(e[0]=[r("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:i(()=>[...e[1]||(e[1]=[r("Limited Gender Clinics",-1)])]),_:1}),a(t,{variant:"green"},{default:i(()=>[...e[2]||(e[2]=[r("Public Healthcare (SSN)",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-italy" tabindex="-1">Healthcare &amp; HRT in Italy <a class="header-anchor" href="#healthcare-hrt-in-italy" aria-label="Permalink to &quot;Healthcare &amp; HRT in Italy&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Italy operates a <strong>gatekeeping model</strong> for transgender healthcare:</p><ul><li><strong>Psychiatric diagnosis required</strong> to start HRT</li><li>Diagnosis followed by a minimum 1-2 year real-life experience and HRT period before surgery</li><li>Treatment centralized at a small number of public gender clinics</li><li>Northern regions have better access than southern regions</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-find-a-gender-clinic" tabindex="-1">Step 1: Find a Gender Clinic <a class="header-anchor" href="#step-1-find-a-gender-clinic" aria-label="Permalink to &quot;Step 1: Find a Gender Clinic&quot;">​</a></h3><p>Contact one of the authorized Gender Identity Centers (Centri di Identità di Genere):</p><ul><li><strong>Careggi University Hospital</strong> — Florence (largest, most experienced)</li><li><strong>San Camillo-Forlanini Hospital</strong> — Rome</li><li><strong>San Raffaele Hospital</strong> — Milan</li><li><strong>Sant&#39;Andrea Hospital</strong> — Rome</li><li><strong>Sant&#39;Orsola-Malpighi Hospital</strong> — Bologna</li></ul><h3 id="step-2-psychological-assessment" tabindex="-1">Step 2: Psychological Assessment <a class="header-anchor" href="#step-2-psychological-assessment" aria-label="Permalink to &quot;Step 2: Psychological Assessment&quot;">​</a></h3><ul><li>3-6 sessions with a psychologist/psychiatrist at the clinic</li><li>Diagnosis of gender dysphoria</li><li>Discussion of treatment goals and timeline</li></ul><h3 id="step-3-hormone-therapy" tabindex="-1">Step 3: Hormone Therapy <a class="header-anchor" href="#step-3-hormone-therapy" aria-label="Permalink to &quot;Step 3: Hormone Therapy&quot;">​</a></h3><ul><li>Endocrinologist prescribes HRT after diagnosis</li><li>Baseline blood tests required</li><li>SSN (Servizio Sanitario Nazionale) covers HRT costs</li><li>Follow-up every 3-6 months</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Careggi University Hospital</td><td>Florence</td><td>Full gender clinic (public)</td></tr><tr><td>San Camillo-Forlanini</td><td>Rome</td><td>Gender clinic (public)</td></tr><tr><td>San Raffaele Hospital</td><td>Milan</td><td>Gender clinic (public)</td></tr><tr><td>Sant&#39;Orsola-Malpighi</td><td>Bologna</td><td>Gender services (public)</td></tr><tr><td>Private endocrinologists</td><td>Nationwide</td><td>HRT (shorter wait times, €100-200)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Italy under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be verified by an Italian doctor; best to bring detailed medical history</li><li><strong>Importing medication</strong>: 3-month supply for personal use with doctor&#39;s letter</li><li><strong>Generic names</strong>: Know estradiol valerate, cyproterone acetate, spironolactone, testosterone gel</li><li><strong>Pharmacies</strong>: Farmacie are widely available; some may need to order specific medications</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries are <strong>covered by public healthcare</strong> with authorization</li><li>Authorization requires: diagnosis + minimum 1-2 years HRT + court approval (for legal change)</li><li>Major surgical centers: Careggi (Florence), San Camillo (Rome), San Raffaele (Milan)</li><li>Public wait times: 12-24 months for consultation, 18-36 months for surgery</li><li>Private surgery: €10,000-30,000</li><li>Facial feminization surgery is generally not covered by public healthcare</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public (SSN)</th><th>Private</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€100-200</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€80-150</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€40-80</td></tr><tr><td>Top surgery</td><td>Covered (public)</td><td>€5,000-10,000</td></tr><tr><td>Bottom surgery</td><td>Covered (public)</td><td>€15,000-30,000</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.aou-careggi.toscana.it/" target="_blank" rel="noreferrer">Careggi Gender Clinic</a></li><li><a href="https://www.mit-italia.it/" target="_blank" rel="noreferrer">MIT (Movimento Identità Trans)</a></li><li><a href="https://www.salute.gov.it/" target="_blank" rel="noreferrer">Italian Ministry of Health</a></li><li><a href="https://www.salute.gov.it/portale/ssn" target="_blank" rel="noreferrer">SSN (National Health Service)</a></li></ul>',22))])}const S=l(c,[["render",h]]);export{f as __pageData,S as default};
